+                let mut data = vec![0.0_f64; numel];
+                for i in 0..rows {
+                    for j in 0..cols {
+                        let exp = if increasing { j } else { cols - 1 - j };
+                        data[i * cols + j] = vals[i].powi(exp as i32);
+                    }
+                }
+                ctx.save_for_backward(vals.to_vec(), vec![rows]);
